var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"읏차. 제대로 받았다.","JPN":"よいしょ。ちゃんと受け止めたよ。","ENG":"Hup! Gotcha.","TWN":"嘿咻，接到啦！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"루루? 쓰러진 거야?","JPN":"ルルちゃん？　倒れたの？","ENG":"Lulu? Is she okay?","TWN":"露露？她是暈倒嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잠든 거야. 정확히는 악몽을 가져오는 중이고…….","JPN":"眠ったんだ。正確には悪夢を取り込んでいるところ……","ENG":"She’s just asleep. Well, gathering nightmares to be exact...","TWN":"是睡著，正確來說是正在帶走惡夢……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"괜찮은 거 맞지?","JPN":"本当に大丈夫なんだよね？","ENG":"But she's fine, right?","TWN":"她不會有事吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"애가 너무 종이처럼 팔랑거려서 걱정돼.","JPN":"紙のようにヒラヒラしてるから心配だなあ。","ENG":"I’m kinda worried because she’s so flimsy.","TWN":"她跟紙片人一樣，站都站不穩，有點不妥的感覺。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그렇지?! 나만 그런 게 아니라니까. 맨날 괜찮다고만 하고, 잘 쓰러지고 비틀대고. 밥도 제대로 안 먹고 잠도 제 때 안 자고. 걱정돼 죽겠어.","JPN":"でしょ！？　やっぱり私だけじゃないんだよ。いつも大丈夫って言って倒れてはふらふらしてるし。ご飯もちゃんと食べないし、ちゃんと寝ないし。もう本当心配で心配で。","ENG":"You are?! I’m not the only one who thinks that! She always claims to be fine, but she frequently faints, wobbles around, doesn't eat well, and doesn't even sleep! She worries me so much.","TWN":"是不是！不是只有我會擔心的嘛！她每次都說沒事，然後一天到晚暈倒，搖搖晃晃的，也不好好睡覺，想把我擔心死。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"푸흡.","JPN":"ぷっ。","ENG":"Pfft!","TWN":"噗。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아. 미안. 걱정된다는 사람 표정치고 너무 괜찮다는 표정이라.","JPN":"あ、ごめん。心配してるというわりには心配ないって顔してるから。","ENG":"Oh, sorry. It’s just that for someone who’s worried, your expression says otherwise.","TWN":"啊，抱歉，因為你嘴巴上說擔心，表情卻很淡定。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그럴 수밖에. 저렇게 걱정시키면서도 항상 멀쩡하게 돌아왔거든.","JPN":"……仕方ないじゃん。あんなに心配させてるくせに、いつも何ともなく帰ってきたんだから。","ENG":"Well... Even though she worries me, she has always returned safely.","TWN":"……沒辦法，雖然我每次都很擔心，但她每次都平安回來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러니까, 믿어. 이번에도 잘 깨어날 거야.","JPN":"だから、信じてる。今度もちゃんと目を覚ますはずだよ。","ENG":"So, I trust her. She’ll be all right this time as well.","TWN":"我相信，她這次也會醒來的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아주 보기 좋네. 구름처럼 몽글몽글해졌어.","JPN":"いい光景だね。雲のようにフワフワになった。","ENG":"That’s nice. Like a fluffy cloud.","TWN":"真美的畫面，好像雲朵一樣軟綿綿的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"나도…….","JPN":"私も……","ENG":"Me too...","TWN":"我也是……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"기분 탓인지 모르겠는데, 바깥이 더 어두워진 것 같지 않아?","JPN":"気のせいかもしれないけど、なんだか外が暗くなった気がしない？","ENG":"Hey, um... Is it just me or did it get darker outside?","TWN":"是我感覺的問題嗎？怎麼覺得外面好像變得更暗了？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러게? 아까보다 훨씬 어두워.","JPN":"そうだね。さっきよりずっと暗い。","ENG":"Yeah... It's gotten significantly darker.","TWN":"對啊，跟剛才比起來，現在又更暗了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시가 뚫어 둔 벽이 꼭 블랙홀처럼 보일 정도로 깜깜해.","JPN":"ドロシーちゃんがあけた穴が、まるでブラックホールに見えるくらい真っ暗だね。","ENG":"That hole in the wall Dorothy made now looks like a black hole.","TWN":"暗到桃樂絲剛踹破的牆壁看起來像黑洞一樣。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……달이 사라졌어. 아까까지만 해도 슈퍼문처럼 떠 있었는데.","JPN":"……月が消えた。さっきまでスーパームーンのように浮いてたのに。","ENG":"The moon’s gone. It was there shining bright a few moments ago...","TWN":"……月亮消失了，剛剛明明還像超級月亮一樣掛在空中。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"뭐?! 구, 구름에 가려진 거 아닐까?","JPN":"えっ！？　く、雲に隠れたんじゃないの？","ENG":"What?! M-maybe it’s just covered by clouds?","TWN":"什麼？！會不會是被雲遮住？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"구름 한 점 없는 날씨였잖아.","JPN":"雲一つなかったけど。","ENG":"There were no clouds in the sky tonight.","TWN":"今天的天氣不是萬里無雲嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"오늘은 개기월식도 아닌데…… 어떻게 된 거지?","JPN":"今日は皆既月食でもないのに……どういうこと？","ENG":"There isn’t a lunar eclipse tonight... What’s going on?","TWN":"也不是月全食……怎麼會這樣？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"달?","JPN":"月？","ENG":"The moon?","TWN":"月亮？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루랑 같이 있을 때도 매일 흐릿했는데……","JPN":"ルルと一緒にいた時にも、毎日ぼんやりしてたけど……","ENG":"It was always blurry when I was with Lulu...","TWN":"我和露露在一起時，月亮也是每天都糊的……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……잠깐?!","JPN":"……ちょっと待って！？","ENG":"Wait...!","TWN":"……等等？！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"생각해 보니까 루루가 항상 멀쩡하게 돌아온 게 아니었어!","JPN":"考えてみれば、ルルっていつも元気に帰ってきたわけじゃなかったんだ！","ENG":"Come to think of it, Lulu wasn’t always all right after she woke up!","TWN":"現在回想起來，露露也不是每次都平安回來的！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤론 님, 아니 헤론에게 능력을 썼을 때 깨어나자마자 다시 기절했는데……!","JPN":"ヘロン様、いや、ヘロンに能力を使ったときは目覚めてすぐまた気絶してた……！","ENG":"When she used her powers on Madam─ I mean, Heron, she fainted right after waking up...!","TWN":"海倫夫人…不對，她對海倫使用能力時，是醒來後又馬上暈過去……！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"얘 왜 아직도 안 일어나? 이번에도 뭐 잘못된 거 아냐?!","JPN":"なんでまだ起きないの？　今度もなんかあったんじゃ！？","ENG":"Why isn’t she waking up? Did something go wrong this time?","TWN":"露露怎麼還沒醒？這次會不會又出什麼差錯？！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"침착해. 곧 깨어날 거야.","JPN":"落ち着いて。すぐ目を覚ますはずだから。","ENG":"Calm down. She’s going to wake up soon.","TWN":"你冷靜點，她很快就會醒過來的。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그걸 어떻게 알아!","JPN":"どうしてわかるの！","ENG":"How do you know that?!","TWN":"你又知道！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"방금까진 믿네 어쩌네 해놓고선.","JPN":"さっきまで信じるとか言ってたくせに。","ENG":"Didn’t you say you trusted her?","TWN":"剛剛是誰說相信她的？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"빈말 아니야. 호흡이 흐트러지고 있어. 점점 깨어나고 있다는 뜻이지.","JPN":"本当だよ。呼吸が乱れてる。目覚めつつあるってことだ。","ENG":"I’m not making it up. Her breathing pattern has changed. That means she’s about to wake up.","TWN":"我不是空口說白話，你看她的呼吸變得沒那麼平穩，就表示她正在醒過來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이것 봐. 맨날 비틀거린다니까?","JPN":"ほら。いつもふらつくんだから。","ENG":"See? She’s always wobbling around like this...","TWN":"看吧！每次都一副癱軟的樣子！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"고마워, 글린다.","JPN":"ありがとう、グリンダ。","ENG":"Thanks, Glinda.","TWN":"格琳達，謝謝你。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"악몽은 어떻게 됐어?","JPN":"悪夢はどうなった？","ENG":"What happened to the nightmares?","TWN":"惡夢處理得如何？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그게…….","JPN":"それが……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"待って。","ENG":"Hang on.","TWN":"你們看！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"으음.","JPN":"うーん。","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"……흐암. 우리가 언제 잠들었던거지……?","JPN":"……ふわあ。私たち、いつの間にか寝ちゃってた……？","ENG":"Huh...? When did we fall asleep...?","TWN":"……呼哈～我們什麼時候睡著的……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"다들 깨어나고 있어.","JPN":"みんな目を覚ましてるよ。","ENG":"The kids, they’re waking up.","TWN":"大家都醒了！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};